import type { CareerQuestion } from "./rrt-questions";

export const sonographyQuestionsBatch5: CareerQuestion[] = [
  { id: "sono-306", stem: "At what gestational age can a gestational sac first be visualized on transvaginal ultrasound?", options: ["4.5-5 weeks", "3 weeks", "7 weeks", "10 weeks"], correctIndex: 0, rationale: "The gestational sac is the earliest sonographic evidence of pregnancy, typically visible by transvaginal ultrasound at 4.5-5 weeks when beta-hCG reaches the discriminatory level of approximately 1,500-2,000 mIU/mL.", difficulty: 1, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-307", stem: "The double decidual sac sign is used to differentiate:", options: ["An intrauterine gestational sac from a pseudogestational sac", "A complete mole from a partial mole", "A corpus luteum cyst from an ectopic pregnancy", "Oligohydramnios from polyhydramnios"], correctIndex: 0, rationale: "The double decidual sac sign consists of two concentric echogenic rings (decidua capsularis and decidua parietalis) surrounding the gestational sac, helping distinguish a true IUP from a pseudogestational sac seen with ectopic pregnancy.", difficulty: 2, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-308", stem: "What is the first structure visible within the gestational sac?", options: ["Yolk sac", "Embryo", "Amnion", "Placenta"], correctIndex: 0, rationale: "The yolk sac is the first structure seen within the gestational sac, typically visible at 5-5.5 weeks transvaginally. It provides early nutrition and hematopoiesis before the placenta develops.", difficulty: 1, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-309", stem: "Cardiac activity should be detected in an embryo with a crown-rump length of:", options: ["≥7 mm", "≥2 mm", "≥15 mm", "≥25 mm"], correctIndex: 0, rationale: "Per current guidelines, cardiac activity should be present when the embryo CRL is ≥7 mm on transvaginal ultrasound. Absence of cardiac activity at this size is diagnostic of early pregnancy failure.", difficulty: 2, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-310", stem: "A blighted ovum (anembryonic pregnancy) is diagnosed when:", options: ["The mean sac diameter is ≥25 mm with no visible embryo", "An embryo is present without cardiac activity", "The yolk sac measures >6 mm", "A subchorionic hemorrhage is present"], correctIndex: 0, rationale: "An anembryonic pregnancy is diagnosed when the mean sac diameter reaches ≥25 mm on TVUS without a visible embryo. This represents a gestational sac that developed but the embryo failed to form.", difficulty: 2, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-311", stem: "Crown-rump length (CRL) is most accurate for gestational age dating during:", options: ["7-10 weeks", "4-5 weeks", "14-16 weeks", "20-24 weeks"], correctIndex: 0, rationale: "CRL measurement between 7-10 weeks provides the most accurate dating with a margin of error of only ±3-5 days. After the first trimester, BPD, HC, AC, and FL are used but with decreasing accuracy.", difficulty: 1, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-312", stem: "An abnormally large yolk sac (>6 mm) in the first trimester is associated with:", options: ["Poor pregnancy outcome", "Normal twin gestation", "Gestational diabetes", "Placenta previa"], correctIndex: 0, rationale: "A yolk sac measuring >6 mm is associated with abnormal pregnancy outcomes including aneuploidy and spontaneous abortion. Normal yolk sac measures 3-5 mm between 5-10 weeks.", difficulty: 3, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-313", stem: "The normal embryonic heart rate at 6-7 weeks gestation is approximately:", options: ["100-120 bpm", "60-80 bpm", "150-180 bpm", "200-220 bpm"], correctIndex: 0, rationale: "At 6-7 weeks, the embryonic heart rate is typically 100-120 bpm. It gradually increases to 140-170 bpm by 9-10 weeks. A heart rate <100 bpm before 6.2 weeks may be normal but warrants follow-up.", difficulty: 2, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-314", stem: "A subchorionic hemorrhage appears sonographically as:", options: ["A crescent-shaped hypoechoic or anechoic collection between the chorion and uterine wall", "A hyperechoic mass within the amniotic cavity", "A cystic mass in the cervix", "Echogenic material within the yolk sac"], correctIndex: 0, rationale: "Subchorionic hemorrhage is blood between the chorion and uterine wall, appearing as a crescent-shaped fluid collection. Echogenicity varies with age: acute is echogenic, older blood becomes hypoechoic/anechoic.", difficulty: 2, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-315", stem: "The interstitial (cornual) ectopic pregnancy is located in:", options: ["The intramural segment of the fallopian tube within the uterine wall", "The fimbrial end of the tube", "The ovary", "The cervix"], correctIndex: 0, rationale: "Interstitial ectopic implants in the proximal intramural portion of the fallopian tube that traverses the myometrium. It is particularly dangerous due to surrounding myometrial vascularity, leading to massive hemorrhage upon rupture.", difficulty: 4, category: "OB/GYN Sonography", topic: "Ectopic Pregnancy" },
  { id: "sono-316", stem: "The 'ring of fire' sign on color Doppler in the adnexa suggests:", options: ["Ectopic pregnancy with prominent peritrophoblastic flow", "Corpus luteum cyst", "Ovarian torsion", "Dermoid cyst"], correctIndex: 0, rationale: "The 'ring of fire' describes a hypervascular ring of color Doppler flow surrounding an ectopic gestational sac, representing peritrophoblastic blood flow. However, a corpus luteum can appear similar, requiring correlation with clinical findings.", difficulty: 3, category: "OB/GYN Sonography", topic: "Ectopic Pregnancy" },
  { id: "sono-317", stem: "The most common location for ectopic pregnancy is:", options: ["Ampullary portion of the fallopian tube", "Isthmic portion of the tube", "Ovary", "Cervix"], correctIndex: 0, rationale: "Approximately 70-80% of ectopic pregnancies occur in the ampullary portion of the fallopian tube. The ampulla is the widest section and the typical site of fertilization.", difficulty: 1, category: "OB/GYN Sonography", topic: "Ectopic Pregnancy" },
  { id: "sono-318", stem: "Heterotopic pregnancy refers to:", options: ["Simultaneous intrauterine and ectopic pregnancies", "Pregnancy in the cervix", "Bilateral ectopic pregnancies", "Pregnancy in the cornual region"], correctIndex: 0, rationale: "Heterotopic pregnancy is the coexistence of an intrauterine pregnancy with an ectopic pregnancy. Its incidence has increased with assisted reproductive technology (up to 1 in 100 ART pregnancies).", difficulty: 3, category: "OB/GYN Sonography", topic: "Ectopic Pregnancy" },
  { id: "sono-319", stem: "A pseudogestational sac differs from a true gestational sac because it:", options: ["Is centrally located within the endometrial cavity and lacks a double decidual sign", "Has a yolk sac visible", "Shows a fetal pole", "Demonstrates a double decidual ring"], correctIndex: 0, rationale: "A pseudogestational sac is a fluid collection in the endometrial cavity caused by decidual reaction from ectopic pregnancy hormones. It is centrally located, lacks the double decidual sign, and has no yolk sac or embryo.", difficulty: 3, category: "OB/GYN Sonography", topic: "Ectopic Pregnancy" },
  { id: "sono-320", stem: "Sonographic findings suggestive of ruptured ectopic pregnancy include:", options: ["Complex free fluid in the cul-de-sac and adnexal mass", "Simple anechoic pelvic fluid only", "Bilateral ovarian cysts", "Endometrial thickening alone"], correctIndex: 0, rationale: "Ruptured ectopic presents with complex (echogenic) free fluid representing hemoperitoneum in the cul-de-sac and Morison's pouch, along with an adnexal mass. Simple fluid may be physiologic; complex fluid indicates hemorrhage.", difficulty: 2, category: "OB/GYN Sonography", topic: "Ectopic Pregnancy" },
  { id: "sono-321", stem: "A complete hydatidiform mole appears sonographically as:", options: ["Echogenic tissue filling the uterus with multiple small cystic spaces ('snowstorm' or 'cluster of grapes' pattern) and no fetus", "Normal gestational sac with embryo", "Large placenta with viable fetus", "Uterine fibroid"], correctIndex: 0, rationale: "Complete mole shows swollen chorionic villi creating a heterogeneous echogenic mass with numerous small anechoic cystic spaces (vesicles) filling the uterus. No fetus or amnion is present. Beta-hCG is markedly elevated.", difficulty: 2, category: "OB/GYN Sonography", topic: "Molar Pregnancy" },
  { id: "sono-322", stem: "A partial mole differs from a complete mole in that it:", options: ["Contains fetal tissue or an abnormal fetus alongside molar tissue", "Has no fetal parts and only swollen villi", "Has markedly higher beta-hCG levels", "Never has theca lutein cysts"], correctIndex: 0, rationale: "Partial mole is triploid and includes an abnormal fetus or fetal parts mixed with focally hydropic villi. Complete mole is diploid (46,XX or 46,XY), has no fetal tissue, and typically has higher hCG and greater malignant potential.", difficulty: 3, category: "OB/GYN Sonography", topic: "Molar Pregnancy" },
  { id: "sono-323", stem: "Theca lutein cysts are associated with molar pregnancy because:", options: ["Markedly elevated beta-hCG stimulates the ovaries", "The molar tissue produces estrogen", "Low progesterone levels cause cyst formation", "Ovarian torsion triggers cyst growth"], correctIndex: 0, rationale: "Extremely high beta-hCG levels in molar pregnancy overstimulate the ovaries, causing bilateral large multiloculated theca lutein cysts. These typically resolve after evacuation as hCG levels decline.", difficulty: 3, category: "OB/GYN Sonography", topic: "Molar Pregnancy" },
  { id: "sono-324", stem: "Following molar pregnancy evacuation, serial beta-hCG monitoring is essential to detect:", options: ["Gestational trophoblastic neoplasia (persistent/invasive mole or choriocarcinoma)", "Recurrent ovarian cysts", "Endometriosis", "Cervical incompetence"], correctIndex: 0, rationale: "After mole evacuation, rising or plateauing beta-hCG suggests persistent GTD or malignant transformation (invasive mole or choriocarcinoma). Serial monitoring continues until hCG is undetectable for 6-12 months.", difficulty: 3, category: "OB/GYN Sonography", topic: "Molar Pregnancy" },
  { id: "sono-325", stem: "Nuchal translucency (NT) screening is performed between:", options: ["11-14 weeks gestation", "6-8 weeks gestation", "18-22 weeks gestation", "28-32 weeks gestation"], correctIndex: 0, rationale: "NT measurement is performed between 11 weeks 0 days and 13 weeks 6 days (CRL 45-84 mm). Increased NT (≥3 mm) is associated with chromosomal abnormalities including trisomy 21, 18, and 13, as well as structural defects.", difficulty: 1, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-326", stem: "An increased nuchal translucency measurement is associated with all of the following EXCEPT:", options: ["Maternal gestational diabetes", "Trisomy 21", "Congenital heart defects", "Turner syndrome"], correctIndex: 0, rationale: "Increased NT is associated with chromosomal abnormalities (trisomies 21, 18, 13; Turner syndrome), congenital heart defects, skeletal dysplasias, and other structural anomalies. Gestational diabetes is not associated with increased NT.", difficulty: 3, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-327", stem: "The biparietal diameter (BPD) is measured from:", options: ["Outer edge of the near calvarium to inner edge of the far calvarium", "Inner to inner edges", "Outer to outer edges", "Center to center of calvaria"], correctIndex: 0, rationale: "BPD is measured at the level of the thalami and cavum septum pellucidum, from the outer edge of the proximal skull to the inner edge of the distal skull (leading edge to leading edge).", difficulty: 2, category: "OB/GYN Sonography", topic: "Second Trimester" },
  { id: "sono-328", stem: "Head circumference (HC) is measured at the level of:", options: ["Thalami and cavum septum pellucidum", "Lateral ventricles only", "Cerebellum", "Orbits"], correctIndex: 0, rationale: "HC is measured at the same level as BPD—through the thalami and cavum septum pellucidum in an axial plane showing a symmetric, oval head shape. The falx cerebri should be midline.", difficulty: 1, category: "OB/GYN Sonography", topic: "Second Trimester" },
  { id: "sono-329", stem: "Abdominal circumference (AC) is measured at the level of:", options: ["The junction of the umbilical vein and portal sinus (J-point)", "The kidneys", "The bladder", "The diaphragm"], correctIndex: 0, rationale: "AC is measured at the level where the umbilical vein enters the portal sinus (J-point), with the stomach visible. A circular cross-section should be obtained with the spine and one to two ribs visible.", difficulty: 2, category: "OB/GYN Sonography", topic: "Second Trimester" },
  { id: "sono-330", stem: "Which biometric parameter is the single best indicator of fetal weight?", options: ["Abdominal circumference", "Biparietal diameter", "Femur length", "Head circumference"], correctIndex: 0, rationale: "AC is the single most sensitive parameter for estimating fetal weight and detecting growth abnormalities. It reflects liver size and subcutaneous fat stores, which are the most variable components of fetal weight.", difficulty: 2, category: "OB/GYN Sonography", topic: "Second Trimester" },
  { id: "sono-331", stem: "The standard anatomy survey (Level II ultrasound) is optimally performed at:", options: ["18-22 weeks gestation", "8-10 weeks gestation", "12-14 weeks gestation", "30-34 weeks gestation"], correctIndex: 0, rationale: "The detailed fetal anatomy survey is best performed at 18-22 weeks when fetal structures are large enough to evaluate but amniotic fluid provides adequate acoustic windows for visualization.", difficulty: 1, category: "OB/GYN Sonography", topic: "Second Trimester" },
  { id: "sono-332", stem: "The 'lemon sign' on fetal cranial ultrasound is associated with:", options: ["Open spina bifida (myelomeningocele)", "Anencephaly", "Hydranencephaly", "Holoprosencephaly"], correctIndex: 0, rationale: "The lemon sign describes frontal bone scalloping creating a lemon-shaped head in axial view. It is an indirect cranial sign of open spina bifida (Chiari II malformation) seen in the second trimester, though it may resolve after 24 weeks.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-333", stem: "The 'banana sign' refers to:", options: ["Abnormal curvature of the cerebellum due to Chiari II malformation", "Normal cerebellar shape", "Enlarged cisterna magna", "Banana-shaped choroid plexus cyst"], correctIndex: 0, rationale: "The banana sign is anterior curvature and compression of the cerebellar hemispheres against the occiput due to hindbrain herniation in Chiari II malformation associated with open spina bifida.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-334", stem: "Anencephaly is characterized sonographically by:", options: ["Absence of the cranial vault above the orbits with exposed brain tissue", "Fluid-filled cranial cavity with intact skull", "Large posterior fossa cyst", "Calcified intracranial mass"], correctIndex: 0, rationale: "Anencephaly shows absence of the calvarium and cerebral hemispheres above the level of the orbits. The face, brainstem, and skull base are present. It is a lethal neural tube defect diagnosable in the first trimester.", difficulty: 1, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-335", stem: "Ventriculomegaly is diagnosed when the lateral ventricular atrium measures:", options: ["≥10 mm", "≥5 mm", "≥15 mm", "≥20 mm"], correctIndex: 0, rationale: "The normal lateral ventricular atrium measures <10 mm throughout gestation. Measurement ≥10 mm defines ventriculomegaly. Mild: 10-12 mm, moderate: 13-15 mm, severe: >15 mm. Causes include aqueductal stenosis, Chiari II, and Dandy-Walker.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-336", stem: "Dandy-Walker malformation is characterized by:", options: ["Enlarged posterior fossa with cystic dilation of the fourth ventricle and absent or hypoplastic cerebellar vermis", "Banana-shaped cerebellum", "Absent corpus callosum only", "Small posterior fossa"], correctIndex: 0, rationale: "Dandy-Walker malformation includes an enlarged posterior fossa, cystic dilation of the fourth ventricle that communicates with the cisterna magna, and complete or partial agenesis of the cerebellar vermis. Hydrocephalus is common.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-337", stem: "Holoprosencephaly results from failure of:", options: ["The prosencephalon (forebrain) to divide into two hemispheres", "Neural tube closure", "The hindbrain to develop", "The cerebellum to form"], correctIndex: 0, rationale: "Holoprosencephaly occurs when the forebrain fails to cleave into two cerebral hemispheres. Three types: alobar (most severe, single ventricle), semilobar, and lobar. Associated with trisomy 13 and midline facial anomalies.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-338", stem: "Choroid plexus cysts are most commonly associated with which chromosomal abnormality when other markers are present?", options: ["Trisomy 18 (Edwards syndrome)", "Trisomy 21 (Down syndrome)", "Trisomy 13 (Patau syndrome)", "Turner syndrome (45,X)"], correctIndex: 0, rationale: "Isolated choroid plexus cysts are common normal variants (1-2% of fetuses) that typically resolve by 26-28 weeks. When associated with other anomalies (clenched fists, heart defects), they increase suspicion for trisomy 18.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-339", stem: "Gastroschisis is differentiated from omphalocele by:", options: ["Herniated bowel not covered by a membrane and defect is to the right of the umbilical cord insertion", "A membrane covering the herniated viscera", "The defect being at the umbilical cord insertion site", "Liver herniation"], correctIndex: 0, rationale: "Gastroschisis has a paraumbilical (usually right-sided) full-thickness abdominal wall defect with free-floating bowel without a covering membrane. Omphalocele is at the cord insertion, covered by a membrane, and may contain liver.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-340", stem: "Omphalocele is associated with chromosomal abnormalities in approximately:", options: ["30-50% of cases", "Less than 5% of cases", "100% of cases", "Only when liver is herniated"], correctIndex: 0, rationale: "Omphalocele has a high rate of associated chromosomal abnormalities (30-50%), particularly trisomies 18 and 13. Gastroschisis has a much lower rate of chromosomal associations. Amniocentesis is recommended for omphalocele.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-341", stem: "Congenital diaphragmatic hernia (CDH) is most commonly:", options: ["Left-sided (Bochdalek hernia) with bowel and/or stomach in the thorax", "Right-sided with liver herniation", "Bilateral", "Anterior (Morgagni hernia)"], correctIndex: 0, rationale: "CDH is most commonly a left posterolateral (Bochdalek) hernia (80-85%). Sonographic findings include fluid-filled stomach or bowel in the left thorax, mediastinal shift to the right, and absent or abnormal diaphragm.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-342", stem: "The four-chamber heart view should demonstrate:", options: ["Two atria, two ventricles of roughly equal size, intact interventricular septum, and apex pointing left", "Three chambers only", "One large ventricle", "The aortic arch"], correctIndex: 0, rationale: "The normal four-chamber view shows symmetric atria and ventricles, intact atrial and ventricular septa, two AV valves, and the cardiac apex pointing to the left. It screens for ~50% of major cardiac anomalies.", difficulty: 1, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-343", stem: "Hypoplastic left heart syndrome (HLHS) on the four-chamber view shows:", options: ["A small, non-functional left ventricle with a dominant right ventricle", "Equally sized ventricles", "A large left ventricle", "A single outflow tract from the left ventricle"], correctIndex: 0, rationale: "HLHS demonstrates a diminutive left ventricle, mitral atresia or stenosis, aortic atresia or stenosis, and a hypoplastic ascending aorta. The right ventricle is dilated and dominant. It is a ductus-dependent lesion.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-344", stem: "An echogenic intracardiac focus (EIF) is most commonly found in which ventricle?", options: ["Left ventricle", "Right ventricle", "Right atrium", "Left atrium"], correctIndex: 0, rationale: "EIF is a small echogenic focus (papillary muscle microcalcification) most commonly in the left ventricle. Isolated EIF is considered a normal variant. When combined with other soft markers, it may increase risk for trisomy 21.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-345", stem: "Bilateral renal agenesis (Potter sequence) is associated with:", options: ["Severe oligohydramnios and non-visualization of the fetal kidneys or bladder", "Polyhydramnios", "Large echogenic kidneys", "Normal amniotic fluid"], correctIndex: 0, rationale: "Bilateral renal agenesis causes absent fetal urine production, leading to severe oligohydramnios (anhydramnios), non-visualization of kidneys and bladder, and resultant pulmonary hypoplasia. It is a lethal condition.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-346", stem: "Multicystic dysplastic kidney (MCDK) appears sonographically as:", options: ["Multiple non-communicating cysts of varying sizes replacing the renal parenchyma", "A single large cyst in the kidney", "Bilateral hydronephrosis", "Echogenic kidneys without cysts"], correctIndex: 0, rationale: "MCDK shows multiple non-communicating cysts of varying sizes without identifiable normal renal parenchyma. The kidney is non-functional. The contralateral kidney may have compensatory hypertrophy.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-347", stem: "Autosomal recessive polycystic kidney disease (ARPKD) appears as:", options: ["Bilaterally enlarged, echogenic kidneys with loss of corticomedullary differentiation", "Multiple large cysts of varying sizes", "Small echogenic kidneys", "Unilateral renal agenesis"], correctIndex: 0, rationale: "ARPKD (infantile type) shows bilaterally enlarged kidneys that are diffusely echogenic due to innumerable microscopic cysts too small to resolve individually. Associated with oligohydramnios and hepatic fibrosis.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-348", stem: "Posterior urethral valves (PUV) are suspected when ultrasound shows:", options: ["Bilateral hydroureteronephrosis with distended thick-walled bladder ('keyhole sign') in a male fetus", "Small bladder in a female fetus", "Unilateral hydronephrosis", "Absent kidneys"], correctIndex: 0, rationale: "PUV occurs exclusively in males. The 'keyhole sign' represents a dilated posterior urethra and bladder. Bilateral hydronephrosis, hydroureters, and oligohydramnios occur from urinary tract obstruction.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-349", stem: "Skeletal dysplasia should be suspected when the femur length is:", options: ["Below the 5th percentile or more than 2 standard deviations below the mean for gestational age", "At the 50th percentile", "Above the 95th percentile", "Equal to the BPD"], correctIndex: 0, rationale: "Short long bones below the 5th percentile raise concern for skeletal dysplasia. Additional findings such as bowing, fractures, decreased mineralization, narrow thorax, and polyhydramnios help differentiate types.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-350", stem: "Thanatophoric dysplasia is characterized by:", options: ["Severe micromelia, narrow thorax, macrocephaly with cloverleaf skull, and curved (telephone receiver) femurs", "Normal bone length with fractures", "Absent mineralization", "Short limbs with polydactyly"], correctIndex: 0, rationale: "Thanatophoric dysplasia is the most common lethal skeletal dysplasia. It features extreme limb shortening, narrow bell-shaped thorax (causing pulmonary hypoplasia), macrocephaly, and characteristic curved femurs.", difficulty: 4, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-351", stem: "Osteogenesis imperfecta type II is identified prenatally by:", options: ["Severely shortened, bowed, and fractured long bones with decreased skull mineralization", "Normal bone length with increased echogenicity", "Isolated clubfoot", "Mild femoral bowing only"], correctIndex: 0, rationale: "OI type II (lethal perinatal form) shows multiple in utero fractures, crumpled long bones, beaded ribs, demineralized calvarium (compressible with transducer pressure), and narrow thorax.", difficulty: 4, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-352", stem: "Duodenal atresia presents on ultrasound as:", options: ["'Double bubble' sign with polyhydramnios", "'Triple bubble' sign", "Absent stomach", "Dilated colon"], correctIndex: 0, rationale: "Duodenal atresia shows the classic 'double bubble' sign representing the distended fluid-filled stomach and proximal duodenum separated by the pylorus. Polyhydramnios results from impaired swallowing absorption. Associated with trisomy 21.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-353", stem: "Fetal cleft lip is best visualized in which ultrasound plane?", options: ["Coronal view of the fetal face", "Sagittal view of the spine", "Axial view of the abdomen", "Transverse view of the extremities"], correctIndex: 0, rationale: "Cleft lip is best demonstrated on coronal views of the fetal face showing disruption of the upper lip. 3D ultrasound provides improved visualization. Cleft palate alone is more difficult to detect sonographically.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-354", stem: "The 'sandal gap' deformity (increased space between first and second toes) is a soft marker for:", options: ["Trisomy 21 (Down syndrome)", "Trisomy 18 (Edwards syndrome)", "Trisomy 13 (Patau syndrome)", "Turner syndrome"], correctIndex: 0, rationale: "A widened gap between the first and second toes ('sandal gap') is a minor soft marker for trisomy 21. Other trisomy 21 markers include thickened nuchal fold, shortened humerus, echogenic bowel, and pyelectasis.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-355", stem: "Echogenic bowel in the second trimester is associated with:", options: ["Cystic fibrosis, chromosomal abnormalities, intraamniotic bleeding, and CMV infection", "Normal finding only", "Maternal diabetes", "Neural tube defects"], correctIndex: 0, rationale: "Echogenic bowel (as bright as bone) is associated with cystic fibrosis, trisomy 21, fetal swallowing of blood from intraamniotic hemorrhage, CMV infection, and IUGR. Isolated echogenic bowel requires further evaluation.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-356", stem: "Placenta previa is defined as the placenta:", options: ["Covering or extending to within 2 cm of the internal cervical os", "Implanting in the fundus", "Separating from the uterine wall", "Having accessory lobes"], correctIndex: 0, rationale: "Placenta previa is diagnosed when the placental edge covers or lies within 2 cm of the internal cervical os on transvaginal ultrasound. Complete previa covers the os entirely. Marginal previa is within 2 cm but not covering.", difficulty: 1, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-357", stem: "The most reliable method to evaluate placenta previa is:", options: ["Transvaginal ultrasound", "Transabdominal ultrasound only", "MRI", "CT scan"], correctIndex: 0, rationale: "Transvaginal ultrasound is the gold standard for diagnosing placenta previa. It provides superior visualization of the relationship between the placental edge and internal cervical os. It is safe and does not increase bleeding risk.", difficulty: 1, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-358", stem: "Placental abruption may appear sonographically as:", options: ["Retroplacental hypoechoic or hyperechoic collection depending on acuity", "Placenta covering the cervical os", "Increased placental thickness only", "Calcifications throughout the placenta"], correctIndex: 0, rationale: "Abruption appears as retroplacental or subchorionic hemorrhage. Acute blood is hyperechoic/isoechoic to placenta (may be missed), subacute becomes hypoechoic. However, ultrasound sensitivity is only 25-50%; clinical diagnosis is often primary.", difficulty: 3, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-359", stem: "Placenta accreta is suspected sonographically when:", options: ["There is loss of the normal hypoechoic retroplacental clear zone with placental lacunae", "The placenta is thin and uniform", "Normal myometrial-placental interface is preserved", "The placenta is calcified"], correctIndex: 0, rationale: "Placenta accreta spectrum shows loss of the retroplacental clear zone, thinning of the myometrium, presence of placental lacunae (irregular vascular spaces), and increased vascularity at the serosa-bladder interface on Doppler.", difficulty: 4, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-360", stem: "Placental lacunae ('Swiss cheese' or 'moth-eaten' appearance) strongly suggest:", options: ["Placenta accreta spectrum", "Normal placental maturation", "Placenta previa without invasion", "Gestational trophoblastic disease"], correctIndex: 0, rationale: "Placental lacunae are irregular intraplacental vascular spaces with turbulent flow on Doppler, creating a 'Swiss cheese' appearance. They are the most predictive sonographic finding for placenta accreta spectrum disorder.", difficulty: 4, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-361", stem: "A succenturiate lobe of the placenta is clinically significant because:", options: ["Vasa previa may occur if connecting vessels cross the internal os", "It always causes preeclampsia", "The fetus will be growth restricted", "It prevents vaginal delivery"], correctIndex: 0, rationale: "A succenturiate (accessory) lobe is connected to the main placenta by membranous vessels. If these vessels cross the cervical os (vasa previa), rupture during labor can cause fatal fetal hemorrhage.", difficulty: 3, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-362", stem: "Vasa previa is diagnosed by:", options: ["Color Doppler showing fetal vessels crossing the internal cervical os", "Thickened placenta", "Polyhydramnios", "Fetal tachycardia"], correctIndex: 0, rationale: "Vasa previa is diagnosed on transvaginal ultrasound with color Doppler demonstrating fetal vessels traversing the membranes over the internal cervical os. It is associated with velamentous cord insertion and succenturiate lobes.", difficulty: 3, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-363", stem: "Velamentous cord insertion refers to:", options: ["Umbilical cord inserting into the fetal membranes rather than the placental disc", "Cord inserting into the center of the placenta", "Two-vessel umbilical cord", "Cord wrapped around the fetal neck"], correctIndex: 0, rationale: "Velamentous insertion occurs when the umbilical vessels traverse the membranes before reaching the placenta, unprotected by Wharton's jelly. It increases risk of vasa previa and vessel rupture during labor.", difficulty: 2, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-364", stem: "A two-vessel umbilical cord (single umbilical artery) is associated with:", options: ["Increased risk of renal anomalies and chromosomal abnormalities", "No clinical significance", "Twin pregnancy only", "Placenta accreta"], correctIndex: 0, rationale: "Single umbilical artery (SUA) occurs in 1% of pregnancies and is associated with renal anomalies, cardiac defects, IUGR, and chromosomal abnormalities. Detailed anatomic survey is recommended when SUA is identified.", difficulty: 2, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-365", stem: "Normal cervical length in the second trimester is:", options: ["≥25 mm", "≥40 mm", "≥10 mm", "≤15 mm"], correctIndex: 0, rationale: "Normal cervical length in the second trimester is ≥25 mm on transvaginal ultrasound. Length <25 mm is considered short and associated with increased risk of preterm delivery. Cerclage may be considered at <25 mm with history.", difficulty: 1, category: "OB/GYN Sonography", topic: "Cervical Assessment" },
  { id: "sono-366", stem: "Cervical funneling refers to:", options: ["Dilation of the internal os with a V- or U-shaped opening of the cervical canal", "Elongation of the cervix", "External os dilation only", "Cervical mass"], correctIndex: 0, rationale: "Funneling is dilation of the internal os creating a funnel shape. The functional cervical length (closed portion below the funnel) determines prematurity risk. Progressive funneling indicates cervical insufficiency.", difficulty: 2, category: "OB/GYN Sonography", topic: "Cervical Assessment" },
  { id: "sono-367", stem: "Cervical length is most accurately measured by:", options: ["Transvaginal ultrasound with an empty bladder", "Transabdominal ultrasound with a full bladder", "Transperineal ultrasound", "MRI"], correctIndex: 0, rationale: "Transvaginal ultrasound is the gold standard for cervical length measurement. A full bladder can artificially elongate the cervix on transabdominal approach. The transducer should not compress the cervix.", difficulty: 1, category: "OB/GYN Sonography", topic: "Cervical Assessment" },
  { id: "sono-368", stem: "Dynamic cervical change assessed during transvaginal ultrasound involves:", options: ["Observing the cervix for shortening or funneling with transfundal pressure or over time", "Measuring once and documenting", "Checking only with a full bladder", "Assessing blood flow to the cervix"], correctIndex: 0, rationale: "Dynamic cervical assessment observes for changes over 3-5 minutes or with fundal pressure/Valsalva. Dynamic shortening or funneling suggests cervical incompetence even if initial length is adequate.", difficulty: 3, category: "OB/GYN Sonography", topic: "Cervical Assessment" },
  { id: "sono-369", stem: "Intrauterine growth restriction (IUGR) is defined as estimated fetal weight:", options: ["Below the 10th percentile for gestational age", "Below the 50th percentile", "Below the 25th percentile", "Above the 90th percentile"], correctIndex: 0, rationale: "IUGR/FGR is defined as EFW <10th percentile for gestational age. Severe FGR is <3rd percentile. Asymmetric IUGR (head-sparing) suggests placental insufficiency; symmetric IUGR suggests early insult or genetic cause.", difficulty: 1, category: "OB/GYN Sonography", topic: "Third Trimester" },
  { id: "sono-370", stem: "In asymmetric IUGR, which measurement lags behind?", options: ["Abdominal circumference", "Head circumference", "Biparietal diameter", "Femur length"], correctIndex: 0, rationale: "In asymmetric (head-sparing) IUGR, caused by placental insufficiency, the AC lags while HC is relatively preserved due to brain-sparing redistribution of blood flow. The HC/AC ratio becomes elevated.", difficulty: 2, category: "OB/GYN Sonography", topic: "Third Trimester" },
  { id: "sono-371", stem: "The middle cerebral artery (MCA) peak systolic velocity is used to assess:", options: ["Fetal anemia", "Fetal heart defects", "Neural tube defects", "Limb anomalies"], correctIndex: 0, rationale: "MCA-PSV >1.5 MoM for gestational age indicates fetal anemia (sensitivity ~100% for moderate-severe anemia). It has replaced invasive amniocentesis for initial assessment of Rh isoimmunization and other causes of fetal anemia.", difficulty: 2, category: "OB/GYN Sonography", topic: "Third Trimester" },
  { id: "sono-372", stem: "The umbilical artery Doppler S/D ratio is normally:", options: ["Decreasing throughout pregnancy as placental resistance decreases", "Increasing throughout pregnancy", "Constant throughout pregnancy", "Absent in normal pregnancy"], correctIndex: 0, rationale: "As pregnancy advances, placental vascular resistance decreases, resulting in increased diastolic flow in the umbilical artery. The S/D ratio therefore normally decreases. Elevated S/D ratio suggests increased placental resistance.", difficulty: 2, category: "OB/GYN Sonography", topic: "Third Trimester" },
  { id: "sono-373", stem: "Absent or reversed end-diastolic flow in the umbilical artery indicates:", options: ["Severe placental insufficiency with high risk of fetal compromise", "Normal placental function", "Polyhydramnios", "Fetal macrosomia"], correctIndex: 0, rationale: "Absent end-diastolic flow (AEDF) or reversed end-diastolic flow (REDF) in the umbilical artery indicates critically elevated placental vascular resistance and is associated with high perinatal morbidity and mortality. Delivery may be indicated.", difficulty: 3, category: "OB/GYN Sonography", topic: "Third Trimester" },
  { id: "sono-374", stem: "The cerebroplacental ratio (CPR) is calculated as:", options: ["MCA PI divided by umbilical artery PI", "Umbilical artery PI divided by MCA PI", "MCA PSV multiplied by UA PSV", "BPD divided by AC"], correctIndex: 0, rationale: "CPR = MCA PI / UA PI. A low CPR (<1.0 or below the 5th percentile) indicates fetal brain-sparing hemodynamic redistribution, suggesting fetal compromise from placental insufficiency even when individual values are normal.", difficulty: 4, category: "OB/GYN Sonography", topic: "Third Trimester" },
  { id: "sono-375", stem: "The biophysical profile (BPP) score of 8/10 with oligohydramnios warrants:", options: ["Delivery if at term, or close surveillance if preterm", "No action needed", "Immediate cesarean at any gestational age", "Repeat in 2 weeks"], correctIndex: 0, rationale: "A BPP of 8/10 with oligohydramnios (AFI scored 0) is concerning. Oligohydramnios indicates chronic compromise. At term, delivery is indicated. Preterm, close surveillance with frequent testing and delivery planning is needed.", difficulty: 3, category: "OB/GYN Sonography", topic: "Third Trimester" },
  { id: "sono-376", stem: "Macrosomia is defined as estimated fetal weight:", options: ["≥4,000-4,500 grams", "≥3,000 grams", "≥2,500 grams", "≥5,500 grams"], correctIndex: 0, rationale: "Macrosomia is generally defined as EFW ≥4,000-4,500 g regardless of gestational age. It increases risk of shoulder dystocia, birth injury, and cesarean delivery. Common causes include gestational diabetes and postdates pregnancy.", difficulty: 1, category: "OB/GYN Sonography", topic: "Third Trimester" },
  { id: "sono-377", stem: "Polyhydramnios is most accurately assessed by:", options: ["Amniotic fluid index (AFI) or single deepest pocket (SDP) measurement", "Subjective visual estimation only", "Uterine fundal height", "Maternal weight gain"], correctIndex: 0, rationale: "Polyhydramnios is defined as AFI >24 cm or SDP >8 cm. SDP is preferred in multiple gestations. Causes include gestational diabetes, fetal GI obstruction, neural tube defects, and fetal hydrops.", difficulty: 1, category: "OB/GYN Sonography", topic: "Third Trimester" },
  { id: "sono-378", stem: "Fetal hydrops is characterized sonographically by:", options: ["Abnormal fluid accumulation in two or more fetal compartments (ascites, pleural effusion, pericardial effusion, skin edema)", "Isolated mild pericardial effusion", "Single area of subcutaneous edema", "Polyhydramnios alone"], correctIndex: 0, rationale: "Hydrops fetalis requires fluid in ≥2 compartments: ascites, pleural effusion, pericardial effusion, or skin edema (>5 mm). May be immune (Rh disease) or non-immune (cardiac failure, anemia, infection, chromosomal). Placentomegaly is common.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-379", stem: "The amniotic fluid index (AFI) is calculated by:", options: ["Summing the deepest vertical pocket in each of four uterine quadrants", "Measuring a single pocket", "Estimating total fluid volume with 3D", "Counting fetal swallowing movements"], correctIndex: 0, rationale: "AFI divides the uterus into four quadrants using the umbilicus and linea nigra. The deepest vertical pocket free of cord and fetal parts is measured in each quadrant and summed. Normal AFI is 5-24 cm.", difficulty: 1, category: "OB/GYN Sonography", topic: "Second Trimester" },
  { id: "sono-380", stem: "A cystic hygroma is most commonly found in the:", options: ["Posterior cervical region (nuchal area)", "Anterior chest wall", "Abdomen", "Extremities"], correctIndex: 0, rationale: "Cystic hygromas are multiloculated lymphatic malformations most commonly located in the posterior cervical/nuchal region. They are strongly associated with Turner syndrome (45,X) and other chromosomal abnormalities.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-381", stem: "Non-immune hydrops is MORE common than immune hydrops and includes which cause?", options: ["Cardiac structural defects and arrhythmias", "Rh isoimmunization only", "ABO incompatibility only", "Anti-Kell antibodies only"], correctIndex: 0, rationale: "Non-immune hydrops accounts for ~90% of hydrops cases. Cardiac anomalies and arrhythmias are the most common causes. Others include chromosomal abnormalities, infections (parvovirus B19), twin-twin transfusion, and thoracic masses.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-382", stem: "Twin-to-twin transfusion syndrome (TTTS) in monochorionic twins is diagnosed by:", options: ["Oligohydramnios in the donor twin and polyhydramnios in the recipient twin", "Both twins having normal fluid", "Discordant fetal sex", "Dichorionic placentation"], correctIndex: 0, rationale: "TTTS occurs in monochorionic diamniotic twins due to unbalanced arteriovenous placental anastomoses. The donor twin has oligohydramnios and a 'stuck' appearance; the recipient has polyhydramnios and may develop hydrops.", difficulty: 3, category: "OB/GYN Sonography", topic: "Second Trimester" },
  { id: "sono-383", stem: "Chorionicity in twin pregnancy is best determined:", options: ["In the first trimester using the lambda (twin peak) or T-sign", "At 36 weeks gestation", "By fetal sex determination only", "By measuring the placental thickness"], correctIndex: 0, rationale: "First trimester is optimal for determining chorionicity. Lambda (twin peak) sign indicates dichorionic placentation (thick membrane with intervening placental tissue). T-sign indicates monochorionic diamniotic (thin membrane without placental tissue).", difficulty: 2, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-384", stem: "The most dangerous type of twin pregnancy is:", options: ["Monochorionic monoamniotic", "Dichorionic diamniotic", "Monochorionic diamniotic", "Dizygotic"], correctIndex: 0, rationale: "Monochorionic monoamniotic twins share both placenta and amniotic sac, carrying the highest risk due to cord entanglement (leading cause of death), TTTS, and prematurity. Mortality rate is 10-20% even with surveillance.", difficulty: 2, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-385", stem: "Placental grading according to Grannum classification includes:", options: ["Grade 0 through Grade III based on calcification and basal plate indentation", "Grade I through Grade V", "Only two grades", "No recognized grading system"], correctIndex: 0, rationale: "Grannum grading: Grade 0 (homogeneous, smooth chorionic plate), Grade I (subtle indentations, scattered calcifications), Grade II (basal plate calcifications, comma-like densities), Grade III (complete indentations, shadowing calcifications). Grade III before 37 weeks may indicate placental dysfunction.", difficulty: 3, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-386", stem: "Circumvallate placenta is characterized by:", options: ["A raised ring of membranes on the fetal surface of the placenta creating a smaller chorionic plate than the basal plate", "A bilobed placenta", "An extra lobe connected by vessels", "A placenta with central depression"], correctIndex: 0, rationale: "Circumvallate placenta has the chorionic plate smaller than the basal plate, with the membranes folding back on themselves creating a raised peripheral ring. It is associated with preterm labor, abruption, and PPROM.", difficulty: 4, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-387", stem: "Gestational trophoblastic disease includes all EXCEPT:", options: ["Placenta previa", "Complete hydatidiform mole", "Partial hydatidiform mole", "Choriocarcinoma"], correctIndex: 0, rationale: "Gestational trophoblastic disease encompasses complete mole, partial mole, invasive mole, choriocarcinoma, and placental site trophoblastic tumor. Placenta previa is an abnormal placental location, not a trophoblastic disease.", difficulty: 1, category: "OB/GYN Sonography", topic: "Molar Pregnancy" },
  { id: "sono-388", stem: "In the first trimester, which finding most reliably diagnoses pregnancy failure?", options: ["CRL ≥7 mm with no cardiac activity on transvaginal ultrasound", "Empty uterus with low beta-hCG", "Small gestational sac with yolk sac", "Subchorionic hemorrhage"], correctIndex: 0, rationale: "Definitive criteria for early pregnancy failure include: CRL ≥7 mm with no cardiac activity, or MSD ≥25 mm with no embryo. These are diagnostic and do not require follow-up imaging for confirmation.", difficulty: 2, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-389", stem: "Cervical ectopic pregnancy appears as:", options: ["Gestational sac within the cervical canal with trophoblastic flow on Doppler", "Gestational sac in the fundus", "An adnexal mass", "An empty uterus with free fluid"], correctIndex: 0, rationale: "Cervical ectopic shows a gestational sac embedded in the cervical stroma below the internal os. The uterus appears 'hourglass' shaped. Color Doppler shows peritrophoblastic flow within the cervix. It is rare but potentially life-threatening.", difficulty: 4, category: "OB/GYN Sonography", topic: "Ectopic Pregnancy" },
  { id: "sono-390", stem: "Cesarean scar ectopic pregnancy is located in:", options: ["The myometrium at the prior cesarean scar in the lower uterine segment", "The fallopian tube", "The ovary", "The upper uterine fundus"], correctIndex: 0, rationale: "Cesarean scar pregnancy implants in the myometrial defect at the prior cesarean scar site in the anterior lower uterine segment. It is diagnosed by an empty uterine cavity and cervical canal with a gestational sac at the scar level.", difficulty: 4, category: "OB/GYN Sonography", topic: "Ectopic Pregnancy" },
  { id: "sono-391", stem: "The normal embryonic heart rate increases to its peak at approximately:", options: ["8-9 weeks gestation", "6 weeks gestation", "12 weeks gestation", "16 weeks gestation"], correctIndex: 0, rationale: "The embryonic heart rate starts at ~100 bpm at 6 weeks, increases to a peak of approximately 170-175 bpm at 8-9 weeks, then gradually decreases to a baseline of ~140-150 bpm by 12-14 weeks.", difficulty: 3, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-392", stem: "Beckwith-Wiedemann syndrome is associated with which fetal finding?", options: ["Macrosomia, omphalocele, macroglossia, and visceromegaly", "Micrognathia and limb reduction", "Bilateral renal agenesis", "Isolated ventriculomegaly"], correctIndex: 0, rationale: "Beckwith-Wiedemann is an overgrowth syndrome characterized by macrosomia, omphalocele, macroglossia, visceromegaly (especially kidneys and liver), and polyhydramnios. It carries an increased risk of embryonal tumors.", difficulty: 4, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-393", stem: "Absent nasal bone on first-trimester ultrasound is a marker for:", options: ["Trisomy 21", "Trisomy 18", "Neural tube defect", "Turner syndrome"], correctIndex: 0, rationale: "Absent or hypoplastic nasal bone in the first trimester is one of the most specific markers for trisomy 21. Approximately 60-70% of fetuses with trisomy 21 have absent nasal bone at 11-14 weeks.", difficulty: 2, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-394", stem: "Second trimester soft markers for trisomy 21 include all EXCEPT:", options: ["Strawberry-shaped skull", "Thickened nuchal fold", "Short humerus", "Echogenic intracardiac focus"], correctIndex: 0, rationale: "Strawberry-shaped skull (narrow frontal and broad occipital diameter) is associated with trisomy 18, not trisomy 21. Trisomy 21 markers include thickened nuchal fold (≥6 mm), short humerus/femur, EIF, echogenic bowel, and renal pyelectasis.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-395", stem: "Trisomy 18 (Edwards syndrome) is associated with which constellation of findings?", options: ["Clenched hands with overlapping fingers, rocker-bottom feet, strawberry-shaped skull, and cardiac defects", "Macrosomia with macroglossia", "Bilateral cleft lip only", "Polydactyly and midline facial defects"], correctIndex: 0, rationale: "Trisomy 18 features include clenched hands (overlapping index over middle finger), rocker-bottom feet, strawberry-shaped skull, cardiac defects (VSD most common), IUGR, choroid plexus cysts, and polyhydramnios.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-396", stem: "Trisomy 13 (Patau syndrome) is characterized by:", options: ["Holoprosencephaly, midline facial defects, polydactyly, and cardiac anomalies", "Clenched fists and rocker-bottom feet", "Cystic hygroma with hydrops only", "Isolated femoral shortening"], correctIndex: 0, rationale: "Trisomy 13 features holoprosencephaly (most characteristic), midline facial defects (cyclopia, proboscis, cleft lip/palate), postaxial polydactyly, echogenic kidneys, cardiac defects, and IUGR. Median survival is 7-10 days.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-397", stem: "Hydrops fetalis secondary to Rh isoimmunization is an example of:", options: ["Immune hydrops", "Non-immune hydrops", "Fetal infection", "Chromosomal abnormality"], correctIndex: 0, rationale: "Immune hydrops results from maternal antibodies (most commonly anti-D/Rh) crossing the placenta and causing fetal red blood cell hemolysis. The resulting severe fetal anemia leads to high-output cardiac failure and hydrops.", difficulty: 1, category: "OB/GYN Sonography", topic: "Third Trimester" },
  { id: "sono-398", stem: "The ductus venosus waveform in the fetus is evaluated to assess:", options: ["Fetal cardiac function and central venous pressure", "Renal function", "Cerebral blood flow", "Placental size"], correctIndex: 0, rationale: "The ductus venosus connects the umbilical vein to the IVC, bypassing the liver. Absent or reversed a-wave in the DV waveform indicates increased cardiac preload/right atrial pressure and is associated with cardiac failure and chromosomal abnormalities.", difficulty: 4, category: "OB/GYN Sonography", topic: "Third Trimester" },
  { id: "sono-399", stem: "Sacrococcygeal teratoma (SCT) appears on ultrasound as:", options: ["A solid and/or cystic mass arising from the fetal sacrococcygeal region", "An intracranial cystic mass", "A chest wall mass", "An isolated limb mass"], correctIndex: 0, rationale: "SCT is the most common congenital tumor, arising from the coccyx. It may be predominantly solid (higher malignancy risk), cystic, or mixed. Large SCTs can cause high-output cardiac failure and hydrops due to vascular steal.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-400", stem: "Congenital cystic adenomatoid malformation (CCAM/CPAM) of the fetal lung appears as:", options: ["A solid or cystic mass within the fetal lung that may cause mediastinal shift", "A fluid collection in the pleural space only", "An absent lung", "A mass in the fetal abdomen"], correctIndex: 0, rationale: "CPAM (congenital pulmonary airway malformation) is a hamartomatous lung lesion classified by cyst size: macrocystic (large cysts), microcystic (appears solid/echogenic). Large lesions cause mediastinal shift and may lead to hydrops.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-401", stem: "Club foot (talipes equinovarus) on prenatal ultrasound appears as:", options: ["The sole of the foot visible in the same plane as the tibia and fibula", "Normal foot position", "Absent foot", "Splayed toes only"], correctIndex: 0, rationale: "In clubfoot, the foot is inverted and plantar-flexed, so the sole faces medially and the foot is seen in the same axial plane as the lower leg bones. It may be isolated or associated with chromosomal or neuromuscular disorders.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-402", stem: "The cerebellar transverse diameter in millimeters roughly correlates with:", options: ["Gestational age in weeks (up to 20 weeks)", "Fetal weight in grams", "Amniotic fluid volume", "Placental grade"], correctIndex: 0, rationale: "The transverse cerebellar diameter in millimeters approximates the gestational age in weeks up to about 20-22 weeks. This is useful as a gestational age-independent measurement, particularly when dates are uncertain.", difficulty: 2, category: "OB/GYN Sonography", topic: "Second Trimester" },
  { id: "sono-403", stem: "Fetal echogenic kidneys bilaterally with normal amniotic fluid may indicate:", options: ["Autosomal dominant polycystic kidney disease (ADPKD)", "Bilateral renal agenesis", "Posterior urethral valves", "Normal kidneys"], correctIndex: 0, rationale: "ADPKD (adult type) may present prenatally with bilaterally enlarged echogenic kidneys but with preserved renal function and normal amniotic fluid, unlike ARPKD which typically causes oligohydramnios.", difficulty: 4, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-404", stem: "Preeclampsia is associated with which Doppler finding in the uterine arteries?", options: ["Persistent bilateral notching and elevated resistance index after 24 weeks", "Low resistance in both uterine arteries", "Absent flow", "Reversed diastolic flow in the MCA"], correctIndex: 0, rationale: "Abnormal uterine artery Doppler (bilateral notching, elevated RI/PI) after 24 weeks reflects poor trophoblastic invasion and inadequate spiral artery remodeling, predicting preeclampsia and IUGR.", difficulty: 3, category: "OB/GYN Sonography", topic: "Third Trimester" },
  { id: "sono-405", stem: "Acrania is diagnosed in the first trimester by:", options: ["Absence of the calvarium with exposed brain tissue visible above the orbits", "Absent cerebellum", "Enlarged posterior fossa", "Short femur length"], correctIndex: 0, rationale: "Acrania (precursor to anencephaly) is the absence of the flat bones of the calvarium with intact but disorganized brain tissue exposed. Diagnosed as early as 11-12 weeks. The brain eventually degenerates to anencephaly.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
];
